void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;
    float L = lum(ret);
    float bw = clamp01(cos(L*27 + 3)*30 - 26);
    float L2 = lum(GetBlur1(vUv));
    float bw2 = clamp01(cos(L*27 + 3)*3 - 6);

    ret = vec3(.1,.6,1.1)*ret.x +
